head.script:
scwin.flagStatus = "";
scwin.hid_kcomcd = "DBEX";
scwin.hid_rfno = "";
scwin.txt_countRow = "";

scwin.onpageload = function() {
    dma_Search.set("kcomcd", scwin.hid_kcomcd);
    ds_AirImportCargoEDIReceiver.insertRow(0);
    scwin.f_Set("INIT");
    ed_blno.setFocus();
};

scwin.onUdcCompleted = function() {
    $c.gus.cfDisableObjects([txt_csnm1, txt_csnm2, txt_wrcvnm]);
};

scwin.f_Set = function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([b_Create, b_Cancel, b_Update, b_Save, b_Delete]);
            $c.gus.cfDisableObjects([txt_csnm1, txt_csnm2, txt_wrcvnm]);
            $c.gus.cfDisableBtnOnly([btn_sendEDI]);
            $c.gus.cfDisableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_DisablePopUpObj();
            break;

        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            $c.gus.cfEnableBtnOnly([b_Create, b_Update]);
            $c.gus.cfEnableBtnOnly([btn_sendEDI]);
            $c.gus.cfDisableBtnOnly([b_Cancel, b_Save, b_Delete]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            break;

        case "RETRIEVE2":
            $c.gus.cfDisableKeyData();
            $c.gus.cfEnableBtnOnly([b_Create]);
            $c.gus.cfDisableBtnOnly([btn_sendEDI]);
            $c.gus.cfDisableBtnOnly([b_Cancel, b_Update, b_Save, b_Delete]);
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            break;

        case "CREATE":
            $c.gus.cfEnableKeyData();
            $c.gus.cfEnableBtnOnly([b_Save, b_Cancel]);
            $c.gus.cfDisableBtnOnly([btn_sendEDI]);
            $c.gus.cfDisableBtnOnly([b_Create, b_Update, b_Delete]);
            $c.gus.cfDisableObjects([lc_lmfGb, txt_lBf, txt_lBf2, txt_lBf3, txt_lBf4, txt_lAf, txt_lAf2, txt_lAf3, txt_lAf4]);
            $c.gus.cfEnableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_EnablePopUpObj();
            break;

        case "UPDATE2":
            $c.gus.cfEnableKeyData();
            $c.gus.cfEnableBtnOnly([b_Save, b_Delete, b_Cancel]);
            $c.gus.cfDisableBtnOnly([b_Create, b_Update]);
            $c.gus.cfDisableBtnOnly([btn_sendEDI]);
            $c.gus.cfEnableObjects([lc_lmfGb, txt_lBf, txt_lBf2, txt_lBf3, txt_lBf4, txt_lAf, txt_lAf2, txt_lAf3, txt_lAf4]);
            $c.gus.cfEnableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_EnablePopUpObj();
            break;

        case "UPDATE":
            $c.gus.cfEnableKeyData();
            $c.gus.cfEnableBtnOnly([b_Save, b_Delete, b_Cancel]);
            $c.gus.cfDisableBtnOnly([b_Create, b_Update]);
            $c.gus.cfDisableBtnOnly([btn_sendEDI]);
            $c.gus.cfEnableBtnOnly([btn_addRowIntnl, btn_undoMarkIntnl, btn_deleteRowIntnl]);
            scwin.f_EnablePopUpObj();
            break;
    }
};

scwin.f_DisablePopUpObj = function() {
    $c.gus.cfDisableObjects([udc_cscd1, udc_cscd2, udc_wrcvcd]);
};

scwin.f_EnablePopUpObj = function() {
    $c.gus.cfEnableObjects([udc_cscd1, udc_cscd2, udc_wrcvcd]);
};

scwin.f_Retrieve = async function() {
    if (ed_blno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House B/L No"]);
        ed_blno.setFocus();
        return;
    }
    dma_Search.set("kcomcd", scwin.hid_kcomcd);
    dma_Search.set("blno", dma_Search.get("blno").trim());
    dma_Search.set("rfno", dma_Search.get("rfno").trim());
    await $c.sbm.execute(sbm_retrieve);
    if (ds_AirImportCargoManifestModify.getRowCount() < 1) {
        return;
    }
    scwin.f_Set("RETRIEVE");

    let row = ds_AirImportCargoManifestModify.getRowPosition();
    if (ds_AirImportCargoManifestModify.getCellData(row, "flag") == "2") {
        if (ed_cscd1.getValue().length > 1) {
            scwin.f_PopUp(1, "T", "F", "F");
        }
        if (ed_cscd2.getValue().length > 1) {
            scwin.f_PopUp(2, "T", "F", "F");
        }
        if (ed_wrcvcd.getValue().length > 1) {
            scwin.f_PopUp(3, "T", "F", "F");
        }
        scwin.f_Set("RETRIEVE2");
    }
};

scwin.f_Create = function() {
    scwin.flagStatus = "CREATE";
    scwin.f_Set("CREATE");
};

scwin.f_Update = function() {
    scwin.f_Set("UPDATE");
    if (ds_AirImportCargoManifestModifyUnit.getRowCount() < 1) {
        $c.gus.cfDisableObjects([lc_lmfGb, txt_lBf, txt_lBf2, txt_lBf3, txt_lBf4, txt_lAf, txt_lAf2, txt_lAf3, txt_lAf4]);
    }
};

scwin.f_Cancel = function() {
    scwin.f_undoRow(ds_AirImportCargoManifestModify);
    scwin.f_undoRow(ds_AirImportCargoManifestModifyUnit);
    let row = ds_AirImportCargoManifestModify.getRowPosition();
    if (ds_AirImportCargoManifestModify.getCellData(row, "flag") == "2") {
        scwin.f_Set("RETRIEVE2");
    } else {
        scwin.f_Set("RETRIEVE");
    }
};

scwin.f_Save = async function() {
    if (await scwin.f_ReqFieldChk()) {
        if (scwin.flagStatus == "CREATE") {
            dma_Search.set("kcomcd", scwin.hid_kcomcd);
            dma_Search.set("mrn", ed_mrn.getValue());
            await $c.sbm.execute(sbm_CollectRFNO);

            let row = ds_AirImportCargoManifestModify.getRowPosition();
            let rfnoRow = ds_CollectRFNO.getRowPosition();
            ds_AirImportCargoManifestModify.setCellData(row, "rfno",
                ds_CollectRFNO.getCellData(rfnoRow, "rfno"));

            if (ds_AirImportCargoManifestModifyUnit.getRowCount() > 0) {
                for (let i = 0; i < ds_AirImportCargoManifestModifyUnit.getRowCount(); i++) {
                    ds_AirImportCargoManifestModifyUnit.setCellData(i, "lmfReason",
                        ds_AirImportCargoManifestModify.getCellData(row, "mfReason"));
                    ds_AirImportCargoManifestModifyUnit.setCellData(i, "rfno",
                        ds_CollectRFNO.getCellData(rfnoRow, "rfno"));
                }
            }
            ds_AirImportCargoManifestModify.setRowStatus(row, "C");
        }

        let row = ds_AirImportCargoManifestModify.getRowPosition();
        ds_AirImportCargoManifestModify.setCellData(row, "kcomcd", scwin.hid_kcomcd);

        if (ds_AirImportCargoManifestModify.getCellData(row, "flag") == "2" || scwin.flagStatus == "CREATE") {
            ds_AirImportCargoManifestModify.setRowStatus(row, "C");
        }

        if (txt_shnm1.getValue().length > 100) {
            await $c.win.alert("Shipper의 첫번째 주소가 100자리를 초과 했습니다. 조정하여 주십시오.");
            txt_shnm1.setFocus();
            return false;
        }

        await $c.sbm.execute(sbm_Save);
        scwin.f_RfnoLoading();
        await scwin.f_Retrieve();
        scwin.flagStatus = "";
    }
};

scwin.f_SendEDI = async function() {
    let flag = 0;
    let flag2 = "999";
    let rtnList = [];
    let chkValidate = await $c.gus.cfValidate([tb_headerMandantory]);
    if (chkValidate) {
        for (let i = 0; i < ds_AirImportCargoManifestModifyUnit.getRowCount(); i++) {
            if (ds_AirImportCargoManifestModifyUnit.getCellData(i, "lmfGb") == "BF") {
                flag = 1;
            }
        }

        let row = ds_AirImportCargoManifestModify.getRowPosition();
        let mfGbVal = ds_AirImportCargoManifestModify.getCellData(row, "mfGb");

        if (mfGbVal == "F" || mfGbVal == "G" || (mfGbVal == "E" && flag > 0)) {
            flag2 = "02";
        } else {
            flag2 = "01";
        }

        let obj = {
            flag: flag2
        };
        rtnList = await $c.win.openPopup("/ui/il/common/jsp/ilCommonEDIRcvSelection.xml", {
            width: 460,
            height: 280,
            modal: true,
            data: obj
        });

        if (rtnList != "999") {
            if (rtnList != null) {
                let ediRow = ds_AirImportCargoEDIReceiver.getRowPosition();
                ds_AirImportCargoEDIReceiver.setCellData(ediRow, "kcomcd",
                    ds_AirImportCargoManifestModify.getCellData(row, "kcomcd"));
                ds_AirImportCargoEDIReceiver.setCellData(ediRow, "rfno",
                    ds_AirImportCargoManifestModify.getCellData(row, "rfno"));
                ds_AirImportCargoEDIReceiver.setCellData(ediRow, "receiver", rtnList);
                await $c.sbm.execute(sbm_SaveReceiver);
                ds_AirImportCargoManifestModify.setRowStatus(row, "C");
                await $c.sbm.execute(sbm_SendEDI);
                ds_AirImportCargoManifestModify.setRowStatus(row, "R");
            }
        }
    }
};

scwin.f_Delete = async function() {
    let chk = await $c.win.confirm(MSG_CM_CRM_004);
    if (chk) {
        let row = ds_AirImportCargoManifestModify.getRowPosition();
        if (ds_AirImportCargoManifestModify.getCellData(row, "flag") == "1") {
            ds_AirImportCargoManifestModify.setRowStatus(row, "U");
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_004, ["대상"]);
        }
        await $c.sbm.execute(sbm_Save);
        scwin.f_RfnoLoading();
        await scwin.f_Retrieve();
    }
};

scwin.f_ReqFieldChk = async function() {
    let chk1 = await $c.gus.cfValidate([tb_headerMandantory]);
    if (!chk1) {
        return false;
    }
    let chk2 = await $c.gus.cfValidate([gr_AirImportCargoManifestModifyUnit]);
    if (!chk2) {
        return false;
    }
    return true;
};

scwin.f_RfnoLoading = function() {
    let param1 = "";
    let param2 = "";
    param1 = ed_blno.getValue().trim();
    param2 = scwin.hid_kcomcd;

    if (param1.length > 0) {
        dma_Search.set("blno", param1);
        dma_Search.set("kcomcd", param2);
        $c.sbm.execute(sbm_RfnoLoading);
    } else {
        ds_Rfno.removeAll();
    }
};

scwin.f_SetDefaultKeyValue = function(ds) {
    let row = ds.getRowPosition();
    let mainRow = ds_AirImportCargoManifestModify.getRowPosition();
    ds.setCellData(row, "kcomcd", scwin.hid_kcomcd);
    ds.setCellData(row, "rfno", ds_AirImportCargoManifestModify.getCellData(mainRow, "rfno"));
    ds.setCellData(row, "lmfReason", ds_AirImportCargoManifestModify.getCellData(mainRow, "mfReason"));
};

scwin.f_addRow = function(ds) {
    scwin.f_Set("UPDATE2");
    $c.data.insertRow(ds);
    scwin.f_SetDefaultKeyValue(ds);
};

scwin.f_deleteRow = function(ds) {
    ds.removeRow(ds.getRowPosition());
};

scwin.f_undoRow = function(ds) {
    let row = ds.getRowPosition();
    if (row >= 0) {
        ds.undoRow(row);
    }
    if (ds == ds_AirImportCargoManifestModifyUnit) {
        $c.gus.cfDisableObjects([lc_lmfGb, txt_lBf, txt_lBf2, txt_lBf3, txt_lBf4, txt_lAf, txt_lAf2, txt_lAf3, txt_lAf4]);
    }
};

scwin.f_PopUp = function(disGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let rtnList = [];
    switch (disGubun) {
        case 1:
            udc_cscd1.ilCommonPopUp(scwin.callbackPopUp1,
                ed_cscd1.getValue().trim(),
                "",
                pWinCloseTF,
                "2",
                "관할세관 Code, 관할세관 Name",
                "130,300",
                "3,4,5,6,7,8,9,10",
                null,
                "500",
                "500",
                null,
                null,
                null,
                pAllSearchTF,
                "관할세관 Search,관할세관 Code, 관할세관 Name",
                pNoDataCloseTF);
            break;
        case 2:
            udc_cscd2.ilCommonPopUp(scwin.callbackPopUp2,
                ed_cscd2.getValue().trim(),
                "",
                pWinCloseTF,
                "2",
                "세관과 Code, 세관과 Name",
                "130,300",
                "3,4,5,6,7,8,9,10",
                null,
                "500",
                "500",
                null,
                null,
                null,
                pAllSearchTF,
                "세관과 Search,세관과 Code, 세관과 Name",
                pNoDataCloseTF);
            break;
        case 3:
            udc_wrcvcd.ilCommonPopUp(scwin.callbackPopUp3,
                ed_wrcvcd.getValue().trim(),
                "",
                pWinCloseTF,
                "4",
                "장치장코드, 장치장명 Name,,ENG",
                "130,200,,100",
                "3,5,6,7,8,9,10",
                null,
                "500",
                "500",
                null,
                null,
                null,
                pAllSearchTF,
                "장치장 Search,장치장코드 Code, 장치장명 Name",
                pNoDataCloseTF);
            break;
    }
};

scwin.callbackPopUp1 = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_cscd1, txt_csnm1);
};

scwin.callbackPopUp2 = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_cscd2, txt_csnm2);
};

scwin.callbackPopUp3 = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_wrcvcd, txt_wrcvnm);
};

scwin.f_BeforePopUpEd = function(nmObj, cdObj, gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let cdObjVal = cdObj.getValue().trim();
    if (cdObjVal == "") {
        nmObj.setValue("");
    } else {
        nmObj.setValue("");
        scwin.f_PopUp(gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF);
    }
};

scwin.f_ChkPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_PopUp(disGubun, "T", "F", "F");
    } else {
        scwin.f_PopUp(disGubun, "T", "F", "F");
    }
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([tb_searchCondition]);
};

scwin.ed_blno_onblur = function(e) {
    scwin.f_RfnoLoading();
};

scwin.ed_cscd1_onblur = function(e) {
    scwin.f_BeforePopUpEd(txt_csnm1, ed_cscd1, 1, "T", "F", "F");
};

scwin.ed_cscd2_onblur = function(e) {
    scwin.f_BeforePopUpEd(txt_csnm2, ed_cscd2, 2, "T", "F", "F");
};

scwin.ed_wrcvcd_onblur = function(e) {
    scwin.f_BeforePopUpEd(txt_wrcvnm, ed_wrcvcd, 3, "T", "F", "F");
};

scwin.sbm_retrieve_submitdone = async function(e) {
    if (ds_AirImportCargoManifestModify.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_Save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
};

scwin.sbm_Save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_Delete_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_004);
};

scwin.sbm_Delete_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_SendEDI_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(E_MSG_CM_INF_018);
};

scwin.sbm_SendEDI_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_CollectRFNO_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_RfnoLoading_submitdone = function(e) {
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.btn_sendEDI_onclick = function(e) {
    scwin.f_SendEDI();
};

scwin.b_Cancel_onclick = function(e) {
    scwin.f_Cancel();
};

scwin.b_Create_onclick = function(e) {
    scwin.f_Create();
};

scwin.b_Update_onclick = function(e) {
    scwin.f_Update();
};

scwin.b_Save_onclick = function(e) {
    scwin.f_Save();
};

scwin.b_Delete_onclick = function(e) {
    scwin.f_Delete();
};

scwin.btn_addRowIntnl_onclick = function(e) {
    scwin.f_addRow(ds_AirImportCargoManifestModifyUnit);
};

scwin.btn_deleteRowIntnl_onclick = function(e) {
    scwin.f_deleteRow(ds_AirImportCargoManifestModifyUnit);
};

scwin.btn_undoMarkIntnl_onclick = function(e) {
    scwin.f_undoRow(ds_AirImportCargoManifestModifyUnit);
};
